#Physics Equationsdef calc_k_eff(fuel_type: str, enrichment: float, rod_percent: float) -> float:    """Estimate effective multiplication factor."""    base_k = 1.05 if fuel_type == "U-235" else 1.02    enrichment_factor = 1 + (enrichment - 0.03) * 5  # tuning parameter    rod_factor = 1 - rod_percent / 100.0    return base_k * enrichment_factor * rod_factordef calc_reactivity(k_eff: float) -> float:    """Return reactivity from effective multiplication factor."""    return (k_eff - 1) / k_effdef evolve_flux(current_flux: float, reactivity: float, leakage_factor: float = 0.97) -> float:    """Update neutron flux based on reactivity and damping."""    return current_flux * (1 + reactivity) * leakage_factordef calc_power_output(flux: float, enrichment: float) -> float:    """Estimate power output from flux and enrichment level."""    energy_per_fission = 3.2e-11  # J    fission_rate = enrichment * 1e24  # tuning scale factor    return flux * energy_per_fission * fission_ratedef calc_coolant_removal(temp: float, coolant_rate: float, inlet_temp: float = 290.0) -> float:    """Approximate Q_cool: energy removed by coolant per timestep."""    coolant_efficiency = 4e5  # J/K/s per unit flow (tunable)    return coolant_efficiency * coolant_rate * (temp - inlet_temp)def calc_temp_change(power: float, coolant_loss: float, core_heat_capacity: float, dt: float) -> float:    """Compute delta T over one time step."""    return (power * dt - coolant_loss * dt) / core_heat_capacity